mapper.select:
SELECT placeId, placeName, category, address, phoneNumber, description, longitude, latitude, imageUrl, viewCount, likeCount FROM ( SELECT t.*, ROWNUM AS rn FROM ( SELECT p.place_id AS placeId, p.place_name AS placeName, p.category, p.address, p.phone_number AS phoneNumber, p.description, p.longitude, p.latitude, p.image_url AS imageUrl, NVL(p.view_count, 0) AS viewCount, (SELECT COUNT(*) FROM likes l WHERE l.target_id = p.place_id AND l.target_type = 'PLACE') AS likeCount FROM place p
AND p.image_url IS NOT NULL
AND p.category = #{category}
AND p.address LIKE #{region} || '%'
AND ( p.place_name LIKE '%' || #{keyword} || '%' OR p.address LIKE '%' || #{keyword} || '%' )
ORDER BY NVL(p.view_count, 0) DESC, p.place_id DESC
ORDER BY likeCount DESC, p.place_id DESC
ORDER BY p.place_id DESC
) t WHERE ROWNUM <= (#{offset} + #{limit}) ) WHERE rn > #{offset}
